let resizeTimeout;function createStars(){let t=document.getElementById("stars-container");t.innerHTML="";for(let e=0;e<200;e++){let e=document.createElement("div");e.className="star";let a=2*Math.random()+1;e.style.width=`${a}px`,e.style.height=`${a}px`,e.style.left=`${100*Math.random()}%`,e.style.top=`${100*Math.random()}%`,e.style.animationDelay=`${3*Math.random()}s`,e.style.animationDuration=`${2*Math.random()+2}s`;let n=Math.floor(3*Math.random())+1;e.setAttribute("data-layer",n),e.style.zIndex=n,t.appendChild(e)}initParallax()}function initParallax(){let t=document.querySelectorAll(".star");window.addEventListener("scroll",function(){let e=-.5*window.pageYOffset;t.forEach(t=>{let a=parseInt(t.getAttribute("data-layer"));t.style.transform=`translateY(${a/3*e}px)`})})}function handleResize(){createStars()}function initContainerParallax(){let t=document.getElementById("stars-container");t&&window.addEventListener("scroll",function(){let e=window.pageYOffset;t.style.transform=`translateY(${.3*e}px)`})}window.addEventListener("load",createStars),window.addEventListener("resize",function(){clearTimeout(resizeTimeout),resizeTimeout=setTimeout(handleResize,250)}),window.addEventListener("load",function(){initContainerParallax()});